patch:
--- a/priority_encoder.v
+++ b/priority_encoder.v
@@ -8,7 +8,7 @@
   output [31:0] encoded_result
 );

-  always @(input_vector or priority_select)
+  always @(*)
   begin
     if (priority_select)
       encoded_result = {input_vector[30:0], 1'b0};

before_code:
module priority_encoder_32bit(
  input [31:0] input_vector,
  input priority_select,
  input invert_flag,
  input enable_encode,
  output [31:0] encoded_result
);

  always @(input_vector or priority_select)
  begin
    if (priority_select)
      encoded_result = {input_vector[30:0], 1'b0};
    else if (invert_flag)
      encoded_result = ~input_vector;
    else if (enable_encode)
      encoded_result = input_vector;
    else
      encoded_result = 32'b0;
  end

endmodule

after_code:
module priority_encoder_32bit(
  input [31:0] input_vector,
  input priority_select,
  input invert_flag,
  input enable_encode,
  output [31:0] encoded_result
);

  always @(*)
  begin
    if (priority_select)
      encoded_result = {input_vector[30:0], 1'b0};
    else if (invert_flag)
      encoded_result = ~input_vector;
    else if (enable_encode)
      encoded_result = input_vector;
    else
      encoded_result = 32'b0;
  end

endmodule
